#include <stdio.h>

int main() {
    int T, N, i, salary, minSalary, sum;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        scanf("%d", &N);
        minSalary = 1000000000;
        int arr[101];
        for (i = 0; i < N; ++i) {
            scanf("%d", &salary);
            arr[i] = salary;
            if (salary < minSalary) minSalary = salary;
        }
        sum = 0;
        for (i = 0; i < N; ++i) {
            sum += arr[i] - minSalary;
        }
        printf("%d\n", sum);
    }
    return 0;
}

