#include <bits/stdc++.h>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; 
    if(!(cin >> T)) return 0;
    while (T--) {
        int N; cin >> N;
        vector<int> a(N);
        int mn = INT_MAX;
        for (int i = 0; i < N; ++i) {
            cin >> a[i];
            mn = min(mn, a[i]);
        }
        long long ans = 0;
        for (int x : a) ans += x - mn;
        cout << ans << '\n';
    }
    return 0;
}

